parameters.jsCode:
const now = new Date();                                                                             
  for (const item of $input.all()) {
    const createdAt = new Date(item.json.created_at);                                                 
    const hoursDiff = (now - createdAt) / (1000 * 60 * 60); 
    item.json.needsReminder = hoursDiff >= 48 ? 'yes' : 'no';
    item.json.hoursSinceCreated = Math.round(hoursDiff);
  }
  return $input.all();
